+            // Simulate new notifications arriving occasionally
+            if (Random.Shared.Next(3) == 0)
+            {
+                var msg = $"New event at {DateTime.UtcNow:HH:mm:ss}";
+                var notification = new Notification(_nextId++, msg, DateTime.UtcNow);
+                _notifications.Add(notification);
+                newer.Add(notification);
+            }
+
+            return Task.FromResult(newer);
+        }
+    }
+}
