 @page "/notifications"
 @rendermode InteractiveServer
 @using BlazorApp.Services
 @inject NotificationService NotificationService
 @implements IDisposable

 <PageTitle>Notifications</PageTitle>

 <h1>Notifications <span class="badge bg-primary">@(Items?.Count ?? 0)</span></h1>

 @if (Items is null)
 {
     <p><em>Loading...</em></p>
 }
 else if (Items.Count == 0)
 {
     <p>No notifications.</p>
 }
 else
 {
     <ul class="list-group">
         @foreach (var n in Items.OrderByDescending(x => x.Timestamp))
         {
             <li class="list-group-item">
                 <strong>@n.Message</strong>
                 <small class="text-muted ms-2">@n.Timestamp.ToString("g")</small>
             </li>
         }
     </ul>
 }

 @code {
     private CancellationTokenSource? _cts;

     [PersistentState]
     public List<Notification>? Items { get; set; }

     protected override async Task OnInitializedAsync()
     {
         // Only fetch if not restored from prerender state
         Items ??= await NotificationService.GetNotificationsAsync();
     }

     protected override void OnAfterRender(bool firstRender)
     {
         if (firstRender)
         {
             // Start polling only after the page is interactive (never during prerender)
             _cts = new CancellationTokenSource();
             _ = PollForNotificationsAsync(_cts.Token);
         }
     }

     private async Task PollForNotificationsAsync(CancellationToken ct)
     {
         while (!ct.IsCancellationRequested)
         {
             await Task.Delay(5000, ct).ConfigureAwait(false);

             if (ct.IsCancellationRequested) break;

             var lastId = Items?.MaxBy(n => n.Id)?.Id ?? 0;
             var newer = await NotificationService.GetNotificationsSinceAsync(lastId);

             if (newer.Count > 0)
             {
                 await InvokeAsync(() =>
                 {
                     Items ??= new();
                     Items.AddRange(newer);
                     StateHasChanged();
                 });
             }
         }
     }

     public void Dispose()
     {
         _cts?.Cancel();
         _cts?.Dispose();
     }
 }

